pub fn url(&self) -> &str {
        &self.base_url
    }
pub async fn search(
        &self,
        query: &str,
        scope_id: &str,
        limit: usize,
    ) -> Result<SearchResponse> {
        let resp = self
            .client
            .post(format!("{}/v1/memories/search", self.base_url))
            .json(&SearchRequest {
                query: query.to_string(),
                scope_id: scope_id.to_string(),
                limit: Some(limit),
            })
            .send()
            .await?
            .error_for_status()?;

        Ok(resp.json().await?)
    }
